def rail_fence_cipher(self, plain_text, rails):
    """
        Cripta il testo in chiaro utilizzando il cifrario Rail Fence.
        :param plain_text: Il testo in chiaro da criptare, str.
        :return: Il testo cifrato, str.
        >>> e = EncryptionUtils("key")
        >>> e.rail_fence_cipher("abc", 2)
        'acb'
        """
    rail = [['\n' for i in range(len(plain_text))] for j in range(rails)]
    dir_down = None
    row, col = (0, 0)
    for char in plain_text:
        if row == 0:
            dir_down = True
        if row == rails - 1:
            dir_down = False
        rail[row][col] = char
        col += 1
        if dir_down:
            row += 1
        else:
            row -= 1
    result = []
    for i in range(rails):
        for j in range(len(plain_text)):
            if rail[i][j] != '\n':
                result.append(rail[i][j])
    return ''.join(result)

def prepare(self, expression):
    """
        Prepara un'espressione in notazione infissa per la conversione in notazione postfissa.
        :param expression: stringa, l'espressione infissa da preparare
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.prepare("2+3*4")

        expression_calculator.postfix_stack = ['2', '3', '4', '*', '+']
        """
    output = []
    operator_stack = []
    for char in expression:
        if char.isdigit() or char == '~':
            output.append(char)
        elif self.is_operator(char):
            while operator_stack and operator_stack[-1] != '(' and self.compare(char, operator_stack[-1]):
                output.append(operator_stack.pop())
            operator_stack.append(char)
        elif char == '(':
            operator_stack.append(char)
        elif char == ')':
            while operator_stack and operator_stack[-1] != '(':
                output.append(operator_stack.pop())
            operator_stack.pop()
    while operator_stack:
        output.append(operator_stack.pop())
    self.postfix_stack = output

@staticmethod
def is_operator(c):
    """
        Controlla se un carattere è un operatore in {'+', '-', '*', '/', '(', ')', '%'}
        :param c: stringa, il carattere da controllare
        :return: bool, True se il carattere è un operatore, False altrimenti
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator.is_operator("+")
        True
        """
    return c in {'+', '-', '*', '\\/', '(', ')', '%'}

@staticmethod
def _calculate(first_value, second_value, current_op):
    """
        Esegue il calcolo matematico basato sugli operandi e sull'operatore forniti
        :param first_value: stringa, il primo operando
        :param second_value: stringa, il secondo operando
        :param current_op: stringa, l'operatore
        :return: decimal.Decimal, il risultato calcolato
        >>> expression_calculator = ExpressionCalculator()
        >>> expression_calculator._calculate("2", "3", "+")
        5.0

        """
    if current_op == '+':
        return Decimal(first_value) + Decimal(second_value)
    elif current_op == '-':
        return Decimal(first_value) - Decimal(second_value)
    elif current_op == '*':
        return Decimal(first_value) * Decimal(second_value)
    elif current_op == '\\/':
        return Decimal(first_value) / Decimal(second_value)
    elif current_op == '%':
        return Decimal(first_value) % Decimal(second_value)

def condition_judge(self):
    """
        Giudica la condizione dell'utente basata sullo standard BMI.
        :return: 1 se l'utente è troppo grasso, -1 se l'utente è troppo magro, 0 se l'utente è normale, int.
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.condition_judge()
        -1
        """
    bmi = self.get_BMI()
    if self.sex == 'male':
        if bmi < 20:
            return -1
        elif bmi > 25:
            return 1
        else:
            return 0
    elif bmi < 19:
        return -1
    elif bmi > 24:
        return 1
    else:
        return 0

def calculate_calorie_intake(self):
    """
        Calcola l'apporto calorico basato sulla condizione dell'utente e sul BMR (Tasso Metabolico Basale). 
        Il BMR è calcolato in base all'altezza, al peso, all'età e al sesso dell'utente; 
        per i maschi è 10 * self.weight + 6.25 * self.height - 5 * self.age + 5, 
        per le femmine è 10 * self.weight + 6.25 * self.height - 5 * self.age - 161. 
        L'apporto calorico è calcolato in base al BMR e alla condizione dell'utente; 
        se l'utente è troppo grasso, l'apporto calorico è BMR * 1.2, 
        se l'utente è troppo magro, l'apporto calorico è BMR * 1.6, 
        se l'utente è normale, l'apporto calorico è BMR * 1.4.
        :return: apporto calorico, float.
        >>> fitnessTracker = FitnessTracker(1.8, 70, 20, "male")
        >>> fitnessTracker.calculate_calorie_intake()
        986.0
        """
    if self.sex == 'male':
        BMR = 10 * self.weight + 6.25 * self.height * 100 - 5 * self.age + 5
    else:
        BMR = 10 * self.weight + 6.25 * self.height * 100 - 5 * self.age - 161
    condition = self.condition_judge()
    if condition == 1:
        return BMR * 1.2
    elif condition == -1:
        return BMR * 1.6
    else:
        return BMR * 1.4

def check_winner(self):
    """
        Controlla se c'è un vincitore cercando cinque in fila in tutte le direzioni (orizzontale, verticale, diagonale).
        return: il simbolo del giocatore vincente (o 'X' o 'O') se c'è un vincitore, altrimenti None.
        >>> gomokuGame = GomokuGame(10)
        >>> moves = [(5, 5), (0, 0), (5, 4), (0, 1), (5, 3), (0, 2), (5, 2), (0, 3), (5, 1)]
        >>> for move in moves:
        ...     gomokuGame.make_move(move[0], move[1])
        >>> gomokuGame.check_winner()
        'X'
        """
    directions = [(0, 1), (1, 0), (1, 1), (1, -1)]
    for row in range(self.board_size):
        for col in range(self.board_size):
            if self.board[row][col] != ' ':
                for direction in directions:
                    if self._check_five_in_a_row(row, col, direction):
                        return self.board[row][col]
    return None

